import { describe, expect, it } from 'vitest';
import { buildPrismPath, buildSlowestPrismPath, maxPossibleDelayMs, analyzePrism } from './temporal-prism';
import { clockDistance, createDistributedClockMesh } from './clock-distributed';
import type { ProcessClock } from './clock-distributed';

// ─── Network Fixture ────────────────────────────────────────────────

const sf: ProcessClock = {
  id: 'pid:sf', label: 'SF',
  location: { lat: 37.77, lon: -122.42, region: 'us-west-1' },
  phase: 'active', localEpochMs: Date.now(), lastHeartbeatMs: Date.now(), requestRate: 100,
};
const ny: ProcessClock = {
  id: 'pid:ny', label: 'NY',
  location: { lat: 40.69, lon: -74.17, region: 'us-east-1' },
  phase: 'active', localEpochMs: Date.now(), lastHeartbeatMs: Date.now(), requestRate: 100,
};
const london: ProcessClock = {
  id: 'pid:london', label: 'London',
  location: { lat: 51.51, lon: -0.13, region: 'eu-west-1' },
  phase: 'active', localEpochMs: Date.now(), lastHeartbeatMs: Date.now(), requestRate: 100,
};
const tokyo: ProcessClock = {
  id: 'pid:tokyo', label: 'Tokyo',
  location: { lat: 35.68, lon: 139.69, region: 'ap-northeast-1' },
  phase: 'active', localEpochMs: Date.now(), lastHeartbeatMs: Date.now(), requestRate: 100,
};
const sydney: ProcessClock = {
  id: 'pid:sydney', label: 'Sydney',
  location: { lat: -33.87, lon: 151.21, region: 'ap-southeast-2' },
  phase: 'active', localEpochMs: Date.now(), lastHeartbeatMs: Date.now(), requestRate: 100,
};

const mesh = createDistributedClockMesh([sf, ny, london, tokyo, sydney]);

describe('buildPrismPath', () => {
  it('builds a path with target delay when feasible', () => {
    // SF to NY direct is ~30ms. Ask for 150ms delivery -- must bounce.
    const path = buildPrismPath(mesh, 'pid:sf', 'pid:ny', 150, { toleranceMs: 50 });
    expect(path).not.toBeNull();
    expect(path!.source).toBe('GnosisTemporalPrism');
    expect(path!.hops.length).toBeGreaterThanOrEqual(1);
    expect(path!.deliveryErrorMs).toBeLessThan(50);
  });

  it('returns null when no path exists (malformed mesh)', () => {
    const emptyMesh = createDistributedClockMesh([sf]);
    const path = buildPrismPath(emptyMesh, 'pid:sf', 'pid:unknown', 100);
    expect(path).toBeNull();
  });

  it('path total delay approximately equals requested delay', () => {
    const path = buildPrismPath(mesh, 'pid:sf', 'pid:tokyo', 250, { toleranceMs: 80 });
    expect(path).not.toBeNull();
    expect(path!.onTime).toBe(true);
  });

  it('direct hop is chosen when delay matches edge weight', () => {
    // Find the direct SF-NY propagation time
    const direct = clockDistance(sf, ny);
    const path = buildPrismPath(mesh, 'pid:sf', 'pid:ny', direct.propagationDelayMs, {
      toleranceMs: 1,
    });
    expect(path).not.toBeNull();
    expect(path!.hops.length).toBe(1); // direct
  });

  it('requires multiple hops for delay longer than any single edge', () => {
    // Find the longest direct edge in the mesh
    const maxEdge = Math.max(...mesh.edges.map(e => e.distance.propagationDelayMs));
    const path = buildPrismPath(mesh, 'pid:sf', 'pid:ny', maxEdge * 1.5, { toleranceMs: maxEdge * 0.5 });
    expect(path).not.toBeNull();
    expect(path!.hops.length).toBeGreaterThanOrEqual(2);
  });

  it('final hop always arrives at target', () => {
    const path = buildPrismPath(mesh, 'pid:sf', 'pid:london', 200, { toleranceMs: 80 });
    expect(path).not.toBeNull();
    const lastHop = path!.hops[path!.hops.length - 1];
    expect(lastHop.toPidId).toBe('pid:london');
  });

  it('each hop starts where the previous ended', () => {
    const path = buildPrismPath(mesh, 'pid:sf', 'pid:sydney', 300, { toleranceMs: 100 });
    expect(path).not.toBeNull();
    for (let i = 1; i < path!.hops.length; i++) {
      expect(path!.hops[i].fromPidId).toBe(path!.hops[i - 1].toPidId);
    }
  });

  it('first hop departs from origin', () => {
    const path = buildPrismPath(mesh, 'pid:sf', 'pid:tokyo', 200);
    expect(path).not.toBeNull();
    expect(path!.hops[0].fromPidId).toBe('pid:sf');
  });

  it('arrival times are monotonically increasing', () => {
    const path = buildPrismPath(mesh, 'pid:sf', 'pid:sydney', 300, { toleranceMs: 100 });
    expect(path).not.toBeNull();
    for (let i = 1; i < path!.hops.length; i++) {
      expect(path!.hops[i].arrivalEpochMs).toBeGreaterThan(
        path!.hops[i - 1].arrivalEpochMs
      );
    }
  });
});

describe('analyzePrism', () => {
  it('counts hops and unique PIDs traversed', () => {
    const path = buildPrismPath(mesh, 'pid:sf', 'pid:tokyo', 250, { toleranceMs: 80 });
    expect(path).not.toBeNull();
    const analysis = analyzePrism(path!, mesh);
    expect(analysis.source).toBe('GnosisPrismAnalysis');
    expect(analysis.hopCount).toBe(path!.hops.length);
    expect(analysis.uniquePidsTraversed).toBeGreaterThanOrEqual(2);
  });

  it('geographic spread is non-negative', () => {
    const path = buildPrismPath(mesh, 'pid:sf', 'pid:tokyo', 250, { toleranceMs: 80 });
    expect(path).not.toBeNull();
    const analysis = analyzePrism(path!, mesh);
    expect(analysis.geographicSpreadDeg).toBeGreaterThanOrEqual(0);
  });

  it('night and rising fractions sum to ≤ 1', () => {
    const path = buildPrismPath(mesh, 'pid:sf', 'pid:tokyo', 250, { toleranceMs: 80 });
    expect(path).not.toBeNull();
    const analysis = analyzePrism(path!, mesh);
    expect(analysis.nightHopFraction + analysis.risingHopFraction).toBeLessThanOrEqual(1);
  });
});

describe('prism properties (reverse-Dijkstra correctness)', () => {
  it('total delay is a sum of edge weights (path budget accounting)', () => {
    const path = buildPrismPath(mesh, 'pid:sf', 'pid:tokyo', 200);
    expect(path).not.toBeNull();
    const sumFromHops = path!.hops.reduce((s, h) => s + h.propagationDelayMs, 0);
    expect(path!.totalDelayMs).toBeCloseTo(sumFromHops, 3);
  });

  it('actual arrival equals start + total delay (temporal consistency)', () => {
    const path = buildPrismPath(mesh, 'pid:sf', 'pid:tokyo', 250, { toleranceMs: 80 });
    expect(path).not.toBeNull();
    expect(path!.actualArrivalEpochMs).toBeCloseTo(
      path!.startEpochMs + path!.totalDelayMs,
      0
    );
  });

  it('delivery error is absolute difference from target', () => {
    const path = buildPrismPath(mesh, 'pid:sf', 'pid:ny', 200, { toleranceMs: 70 });
    expect(path).not.toBeNull();
    const expectedError = Math.abs(path!.actualArrivalEpochMs - path!.deliverAtEpochMs);
    expect(path!.deliveryErrorMs).toBeCloseTo(expectedError, 3);
  });

  it('onTime flag matches tolerance check', () => {
    const tol = 50;
    const path = buildPrismPath(mesh, 'pid:sf', 'pid:tokyo', 200, { toleranceMs: tol });
    expect(path).not.toBeNull();
    expect(path!.onTime).toBe(path!.deliveryErrorMs <= tol);
  });
});

// ─── Slowest Path ───────────────────────────────────────────────────

describe('buildSlowestPrismPath', () => {
  it('produces a valid prism path', () => {
    const path = buildSlowestPrismPath(mesh, 'pid:sf', 'pid:ny');
    expect(path).not.toBeNull();
    expect(path!.source).toBe('GnosisTemporalPrism');
    expect(path!.hops.length).toBeGreaterThanOrEqual(1);
  });

  it('visits more nodes than the fastest direct path', () => {
    const slowest = buildSlowestPrismPath(mesh, 'pid:sf', 'pid:ny');
    expect(slowest).not.toBeNull();
    // With 5 nodes in mesh, slowest should use intermediates
    expect(slowest!.hops.length).toBeGreaterThanOrEqual(2);
  });

  it('final hop always arrives at target', () => {
    const path = buildSlowestPrismPath(mesh, 'pid:sf', 'pid:tokyo');
    expect(path).not.toBeNull();
    expect(path!.hops[path!.hops.length - 1].toPidId).toBe('pid:tokyo');
  });

  it('visits each intermediate node at most once', () => {
    const path = buildSlowestPrismPath(mesh, 'pid:sf', 'pid:ny');
    expect(path).not.toBeNull();
    const visited = new Set<string>(['pid:sf']);
    for (const hop of path!.hops) {
      expect(visited.has(hop.toPidId) && hop.toPidId !== path!.targetPidId).toBe(false);
      visited.add(hop.toPidId);
    }
  });

  it('witnessAll visits every PID in the mesh', () => {
    const path = buildSlowestPrismPath(mesh, 'pid:sf', 'pid:ny', {
      witnessAll: true,
    });
    expect(path).not.toBeNull();
    const visitedIds = new Set<string>(['pid:sf']);
    for (const hop of path!.hops) visitedIds.add(hop.toPidId);
    // Should include all 5 mesh nodes
    expect(visitedIds.size).toBe(mesh.clocks.length);
  });

  it('respects maxHops ceiling', () => {
    const path = buildSlowestPrismPath(mesh, 'pid:sf', 'pid:ny', {
      maxHops: 2, // origin hop + target hop only
    });
    expect(path).not.toBeNull();
    expect(path!.hops.length).toBeLessThanOrEqual(2);
  });

  it('respects ceilingMs', () => {
    const path = buildSlowestPrismPath(mesh, 'pid:sf', 'pid:ny', {
      ceilingMs: 1000,
    });
    expect(path).not.toBeNull();
    expect(path!.totalDelayMs).toBeLessThanOrEqual(1000);
  });

  it('slowest path is strictly longer than direct hop', () => {
    // Direct hop delay
    const direct = buildPrismPath(mesh, 'pid:sf', 'pid:ny',
      Math.min(...mesh.edges.filter(e => (e.fromId === 'pid:sf' && e.toId === 'pid:ny') || (e.fromId === 'pid:ny' && e.toId === 'pid:sf')).map(e => e.distance.propagationDelayMs)),
      { toleranceMs: 1 }
    );
    const slowest = buildSlowestPrismPath(mesh, 'pid:sf', 'pid:ny');
    expect(direct).not.toBeNull();
    expect(slowest).not.toBeNull();
    expect(slowest!.totalDelayMs).toBeGreaterThan(direct!.totalDelayMs);
  });

  it('deliveryErrorMs is 0 for slowest path (no target miss)', () => {
    const path = buildSlowestPrismPath(mesh, 'pid:sf', 'pid:ny');
    expect(path!.deliveryErrorMs).toBe(0);
    expect(path!.onTime).toBe(true);
  });

  it('returns null when origin or target missing', () => {
    expect(buildSlowestPrismPath(mesh, 'pid:ghost', 'pid:ny')).toBeNull();
    expect(buildSlowestPrismPath(mesh, 'pid:sf', 'pid:ghost')).toBeNull();
  });
});

describe('maxPossibleDelayMs', () => {
  it('returns a positive number for a valid origin/target', () => {
    const maxMs = maxPossibleDelayMs(mesh, 'pid:sf', 'pid:ny');
    expect(maxMs).toBeGreaterThan(0);
  });

  it('is at least the direct edge delay', () => {
    const edgeSfNy = mesh.edges.find(e =>
      (e.fromId === 'pid:sf' && e.toId === 'pid:ny') ||
      (e.fromId === 'pid:ny' && e.toId === 'pid:sf')
    );
    const direct = edgeSfNy!.distance.propagationDelayMs;
    const maxMs = maxPossibleDelayMs(mesh, 'pid:sf', 'pid:ny');
    expect(maxMs).toBeGreaterThanOrEqual(direct);
  });

  it('returns 0 for unknown origin/target', () => {
    expect(maxPossibleDelayMs(mesh, 'pid:ghost', 'pid:ny')).toBe(0);
  });
});
